function todayStr() {
  const d = new Date();
  return d.toISOString().slice(0, 10);
}
function nowTimeStr() {
  const d = new Date();
  return d.toTimeString().slice(0, 5);
}
function fmtINR(n) {
  if (n === "" || n === null || n === undefined || isNaN(n)) return "-";
  return Number(n).toLocaleString("en-IN");
}
function uid() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2, 8);
}

