export default function App() {
  const [view, setView] = useState("staff"); // staff | owner | login
  const [loginEmail, setLoginEmail] = useState("");
  const [loginPassword, setLoginPassword] = useState("");
  const [loginError, setLoginError] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [isRemembered, setIsRemembered] = useState(false);

  return (
    <div className="min-h-screen bg-stone-100" style={{ fontFamily: "'Source Sans 3', 'Segoe UI', sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Source+Sans+3:wght@400;500;600;700&family=Fraunces:wght@500;600;700&display=swap');
        .ff-display { font-family: 'Fraunces', serif; }
      `}</style>

      <header className="sticky top-0 z-30 bg-stone-900 text-stone-100">
        <div className="max-w-3xl mx-auto px-4 py-3 flex items-center justify-between">
          <div className="flex items-center gap-2.5">
            <div className="w-9 h-9 rounded-md bg-white flex items-center justify-center overflow-hidden shrink-0">
              <img src={LOGO_DATA_URI} alt="Panchanan International" className="w-full h-full object-contain" />
            </div>
            <div>
              <div className="ff-display text-[15px] font-semibold leading-tight">Panchanan International Pvt Ltd</div>
              <div className="text-[11px] text-stone-400 leading-tight">Attendance &amp; Daily Sales</div>
            </div>
          </div>
          <div className="flex rounded-lg bg-stone-800 p-0.5 text-[13px] font-medium">
            <button
              onClick={() => setView("staff")}
              className={`px-3 py-1.5 rounded-md transition ${view === "staff" ? "bg-amber-600 text-stone-950" : "text-stone-300"}`}
            >
              Staff
            </button>
            <button
              onClick={() => setView(view === "owner" ? "owner" : isRemembered ? "owner" : "login")}
              className={`px-3 py-1.5 rounded-md transition flex items-center gap-1 ${view === "owner" ? "bg-amber-600 text-stone-950" : "text-stone-300"}`}
            >
              <Lock size={12} /> Owner
            </button>
          </div>
        </div>
      </header>

      {view === "staff" && <StaffForm />}
      {view === "login" && (
        <LoginGate
          email={loginEmail}
          setEmail={setLoginEmail}
          password={loginPassword}
          setPassword={setLoginPassword}
          loginError={loginError}
          rememberMe={rememberMe}
          setRememberMe={setRememberMe}
          onSubmit={() => {
            if (loginEmail.trim().toLowerCase() === OWNER_USERNAME.toLowerCase() && loginPassword === OWNER_PASSWORD) {
              setLoginError(false);
              if (rememberMe) setIsRemembered(true);
              setView("owner");
            } else {
              setLoginError(true);
            }
          }}
        />
      )}
      {view === "owner" && (
        <OwnerDashboard
          onLogout={() => {
            setIsRemembered(false);
            setLoginEmail("");
            setLoginPassword("");
            setRememberMe(false);
            setView("staff");
          }}
        />
      )}
    </div>
  );
}

